from collections import Counter

# 1. Reverse a string
def reverse_string(s):
    return s[::-1]

print(reverse_string("hello"))  # 'olleh'

# 2. Check palindrome
def is_palindrome(s):
    s = s.lower().replace(" ", "")
    return s == s[::-1]

print(is_palindrome("racecar"))   # True
print(is_palindrome("A man a plan a canal Panama".replace(" ", "")))  # True

# 3. Character frequency
def char_frequency(s):
    return dict(Counter(s))

print(char_frequency("hello"))  # {'h': 1, 'e': 1, 'l': 2, 'o': 1}

# 4. First non-repeating character
def first_unique(s):
    counts = Counter(s)
    for char in s:
        if counts[char] == 1:
            return char
    return None

print(first_unique("aabbcdd"))  # 'c'
print(first_unique("aabb"))     # None

# 5. Check if two strings are anagrams
def is_anagram(a, b):
    return Counter(a.lower()) == Counter(b.lower())

print(is_anagram("listen", "silent"))  # True
print(is_anagram("hello", "world"))   # False

# 6. Remove duplicate characters preserving order
def remove_duplicates(s):
    return ''.join(dict.fromkeys(s))

print(remove_duplicates("abracadabra"))  # 'abrcd'

# 7. Count vowels and consonants
def count_vowels_consonants(s):
    s = s.lower()
    vowels = sum(1 for c in s if c in 'aeiou')
    consonants = sum(1 for c in s if c.isalpha() and c not in 'aeiou')
    return vowels, consonants

print(count_vowels_consonants("Hello World"))  # (3, 7)

# 8. Check if string has all unique characters
def all_unique(s):
    return len(s) == len(set(s))

print(all_unique("abcdef"))  # True
print(all_unique("aabcde"))  # False

# 9. Longest common prefix
def longest_common_prefix(strs):
    if not strs:
        return ""
    prefix = strs[0]
    for s in strs[1:]:
        while not s.startswith(prefix):
            prefix = prefix[:-1]
            if not prefix:
                return ""
    return prefix

print(longest_common_prefix(["flower", "flow", "flight"]))  # 'fl'

# 10. Compress a string (run-length encoding)
def compress(s):
    if not s:
        return ""
    result = []
    count = 1
    for i in range(1, len(s)):
        if s[i] == s[i-1]:
            count += 1
        else:
            result.append(f"{s[i-1]}{count}" if count > 1 else s[i-1])
            count = 1
    result.append(f"{s[-1]}{count}" if count > 1 else s[-1])
    return ''.join(result)

print(compress("aabbbcccc"))  # 'a2b3c4'
